const express = require('express');
const bodyParser = require('body-parser');
const { Pool } = require('pg');

const app = express();
app.use(bodyParser.json());

const pool = new Pool({
  user: 'your_db_user',
  host: 'your_db_host',
  database: 'your_db_name',
  password: 'your_db_password',
  port: your_db_port,
});

async function redeemCoupon(userId, couponCode) {
  await pool.query('BEGIN');

  try {
    const result = await pool.query(
      `
        UPDATE coupons
        SET used = true
        WHERE code = $1 AND user_id IS NULL AND expiration_date > NOW()
        RETURNING discount;
      `,
      [couponCode]
    );

    if (result.rows.length === 0) {
      throw new Error('Invalid or expired coupon');
    }

    const { discount } = result.rows[0];

    await pool.query(
      `
        UPDATE users
        SET balance = balance - $1
        WHERE id = $2;
      `,
      [discount, userId]
    );

    await pool.query('COMMIT');

    return discount;
  } catch (error) {
    await pool.query('ROLLBACK');
    throw error;
  }
}

app.post('/redeem-coupon', async (req, res) => {
  const { userId, couponCode } = req.body;

  try {
    const discount = await redeemCoupon(userId, couponCode);
    res.json({ message: 'Coupon redeemed successfully', discount });
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
});

